{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"],
    "confirmed_decisions": [
      {
        "decision": "스모크 테스트가 통과하면 공개 릴리스 목표 시점은 금요일 15:00 KST로 한다.",
        "conditions": ["스모크 테스트 통과"]
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인한다.",
        "conditions": ["packageName mismatch 발생 시"]
      },
      {
        "decision": "계약 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다.",
        "conditions": ["패키지 계약이 잘못되었다고 확인된 경우"]
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName mismatch를 무시하도록 변경한다.",
        "proposed_by": "Hara",
        "outcome": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "proposed_by": "Seoyeon",
        "status": "internal stretch goal only",
        "reason": "Doyun이 스모크 테스트 통과가 먼저 필요하다고 이의 제기함"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차를 목요일까지 검토하면 좋다는 의견이 있었으나 담당자는 지정되지 않았다."
      },
      {
        "item": "최종 릴리스 승인 권한자는 결정되지 않았다."
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부는 결정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래된 경우 릴리스 노트가 사용자를 오도할 수 있다."
      }
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed from raw notes"
    },
    {
      "owner": "Doyun",
      "task": "action_items.md에 실패 triage note를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed from raw notes"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "confirmed, no exact deadline set",
      "source_certainty": "confirmed from raw notes"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 if possible",
      "status": "suggested, no owner assigned",
      "source_certainty": "mentioned but not assigned"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 금요일 10:00 KST 스모크 테스트 결과를 확인한다.",
      "스모크 테스트 실패 시 Doyun의 action_items.md 실패 triage note를 확인한다.",
      "스모크 결과 게시 후 Hara의 generated tarball path 확인 결과를 확인한다.",
      "README 설치 절차 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 확인한다.",
      "릴리스 노트에 내부 수요일 stretch goal을 포함할지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너",
      "예산",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": {
    "customer": "고객 또는 외부 파트너는 언급되지 않았으므로 생성하지 않는다.",
    "budget": "예산 정보는 언급되지 않았으므로 생성하지 않는다.",
    "security": "보안 사고는 언급되지 않았으므로 생성하지 않는다.",
    "outage": "프로덕션 장애는 언급되지 않았으므로 생성하지 않는다.",
    "legal": "법무 승인 요구사항은 언급되지 않았으므로 생성하지 않는다.",
    "owners": "명시된 담당자만 owner로 기록하고, README 검토 담당자는 null로 둔다.",
    "deadlines": "명시된 마감만 기록하고, Hara 작업에는 정확한 마감일을 만들지 않는다."
  }
}
